from pathlib import Path
import csv
import json


# Repository root:
# video-perception-pipeline/
REPO_ROOT = Path(__file__).resolve().parents[1]

# Input generated by the temporal tracking pipeline
TRACKED_DETECTIONS_CSV = (
    REPO_ROOT / "outputs" / "tracks" / "tracked_detections.csv"
)

# Metadata generated by frame sampling.
# This is the source of truth for timestamps.
FRAME_METADATA_CSV = (
    REPO_ROOT / "outputs" / "frames" / "frame_metadata.csv"
)

# Final prediction export required by the assignment
PREDICTIONS_JSONL = REPO_ROOT / "outputs" / "predictions.jsonl"

# Description of the perception pipeline used to generate predictions.
METHOD_NAME = "YOLO + IoU Tracker"


def load_frame_metadata():
    """
    Load sampled-frame metadata generated by sample_frames.py.

    The key point:
    frame_index is the ORIGINAL video frame index.
    timestamp_sec is computed as:

        original_frame_index / original_video_fps

    Returns:
        dict keyed by (video_id, frame_name)
    """

    if not FRAME_METADATA_CSV.exists():
        raise FileNotFoundError(
            f"Frame metadata not found: {FRAME_METADATA_CSV}. "
            "Run frame sampling first: python3 src/sample_frames.py"
        )

    metadata = {}

    with open(
        FRAME_METADATA_CSV,
        "r",
        encoding="utf-8",
    ) as f:

        reader = csv.DictReader(f)

        for row in reader:

            key = (
                row["video_id"],
                row["frame_name"],
            )

            metadata[key] = {
                "timestamp_sec": float(row["timestamp_sec"]),
                "fps": float(row["fps"]),
                "original_frame_index": int(row["original_frame_index"]),
                "sampled_frame_number": int(row["sampled_frame_number"]),
            }

    return metadata


def build_notes(row):
    """
    Generate optional reviewer notes.
    """

    notes = []

    if row["is_new_track"] == "True":
        notes.append("new track")

    missed_frames = int(
        row["missed_frames_before_match"]
    )

    if missed_frames > 0:
        notes.append(
            "possible occlusion or re-entry"
        )

    return "; ".join(notes)


def export_predictions():
    """
    Export tracked detections to JSONL format.

    Reads:
        outputs/tracks/tracked_detections.csv
        outputs/frames/frame_metadata.csv

    Writes:
        outputs/predictions.jsonl

    One JSON object is written per line.
    """

    if not TRACKED_DETECTIONS_CSV.exists():
        raise FileNotFoundError(
            f"Tracked detections not found: "
            f"{TRACKED_DETECTIONS_CSV}. "
            "Run the temporal tracking pipeline first."
        )

    frame_metadata = load_frame_metadata()

    predictions = []

    with open(
        TRACKED_DETECTIONS_CSV,
        "r",
        encoding="utf-8",
    ) as f:

        reader = csv.DictReader(f)

        for row in reader:

            frame_index = int(
                row["frame_index"]
            )

            metadata_key = (
                row["video_id"],
                row["frame_name"],
            )

            if metadata_key not in frame_metadata:
                raise KeyError(
                    f"Missing frame metadata for: {metadata_key}. "
                    "Re-run src/sample_frames.py and then rerun the pipeline."
                )

            metadata = frame_metadata[metadata_key]

            prediction = {
                "video_id": row["video_id"],

                # Original frame index in the source video.
                "frame_index": frame_index,

                # Correct timestamp from sampling metadata.
                "timestamp_sec": metadata["timestamp_sec"],

                # Extra metadata for reproducibility and debugging.
                "sampled_frame_number": metadata["sampled_frame_number"],
                "fps": metadata["fps"],

                "class_label": row["class_name"],
                "box": [
                    float(row["x1"]),
                    float(row["y1"]),
                    float(row["x2"]),
                    float(row["y2"]),
                ],
                "track_id": int(
                    row["track_id"]
                ),
                "confidence": float(
                    row["confidence"]
                ),
                "method": METHOD_NAME,
                "notes": build_notes(row),
            }

            predictions.append(
                prediction
            )

    PREDICTIONS_JSONL.parent.mkdir(
        parents=True,
        exist_ok=True,
    )

    with open(
        PREDICTIONS_JSONL,
        "w",
        encoding="utf-8",
    ) as f:

        for prediction in predictions:

            f.write(
                json.dumps(prediction)
                + "\n"
            )

    print(
        f"Exported {len(predictions)} predictions"
    )

    print(
        f"Predictions saved to: "
        f"{PREDICTIONS_JSONL}"
    )


def main():
    """
    Prediction export pipeline.

    1. Load tracked detections.
    2. Load frame timestamp metadata.
    3. Convert detections into the required JSONL schema.
    4. Export predictions.jsonl.
    """

    export_predictions()


if __name__ == "__main__":
    main()